html:
{% set company_currency = frappe.db.get_value("Company", doc.company, "default_currency") or "AED" %}
{% set party_name = doc.party_name or doc.party %}

{# Check if payment mode is TR or LC #}
{% set is_tr_payment = False %}
{% set is_lc_payment = False %}
{% if doc.payment_mode %}
    {% set mode_of_payment = frappe.db.get_value("Mode of Payment", doc.payment_mode, ["custom_is_tr", "custom_is_lc"], as_dict=True) or {} %}
    {% set is_tr_payment = mode_of_payment.get("custom_is_tr", 0) %}
    {% set is_lc_payment = mode_of_payment.get("custom_is_lc", 0) %}
{% endif %}

{# Fetch payment history #}
{% set payment_history = frappe.call("avientek.avientek.doctype.payment_request_form.payment_request_form.get_supplier_payment_history", supplier=doc.party, company=doc.company, limit=10) or [] %}

{# Get Previous Payment Details attachment from first row #}
{% set first_row = doc.payment_references[0] if doc.payment_references else None %}
{% set prev_payment_attachment = first_row.previous_payment_details if first_row else None %}
{% set prev_payment_images = [] %}
{% if prev_payment_attachment %}
    {% set prev_payment_images = frappe.call("avientek.avientek.doctype.payment_request_form.payment_request_form.get_attachment_as_images", file_url=prev_payment_attachment, max_pages=5) or [] %}
{% endif %}

{# Batch pre-fetch ALL attachment images in one call for performance #}
{% set all_attachments = frappe.call("avientek.avientek.doctype.payment_request_form.payment_request_form.get_all_print_attachments", docname=doc.name) or {} %}

{# Fetch party details dynamically based on party_type #}
{% set party_doc = frappe.get_doc(doc.party_type, doc.party) if doc.party and doc.party_type else {} %}
{% set party_address = doc.address_display or "" %}
{% set party_label = doc.party_type or "Party" %}

{# Fetch supplier bank details with full info #}
{% set supplier_bank = frappe.db.get_value("Bank Account", {"party_type": doc.party_type, "party": doc.party, "is_default": 1}, ["name", "bank", "bank_account_no", "iban", "branch_code"], as_dict=True) or {} %}
{% set supplier_swift = "" %}
{% if supplier_bank and supplier_bank.bank %}
    {% set supplier_swift = frappe.db.get_value("Bank", supplier_bank.bank, "swift_number") or "" %}
{% endif %}

{# Get issued bank details #}
{% set issued_bank_details = frappe.db.get_value("Bank Account", doc.issued_bank, ["bank", "bank_account_no", "iban"], as_dict=True) or {} %}
{% set issued_bank_currency = frappe.db.get_value("Bank Account", doc.issued_bank, "account_currency") or company_currency %}

<style>
    * {
        box-sizing: border-box;
    }

    @page {
        size: A4;
        margin: 10mm;
    }

    html, body {
        margin: 0;
        padding: 0;
    }

    /* Hide ALL checkboxes and input elements */
    input, input[type="checkbox"], .checkbox, [type="checkbox"] {
        display: none !important;
        visibility: hidden !important;
        width: 0 !important;
        height: 0 !important;
        position: absolute !important;
        left: -9999px !important;
    }

    .print-format-container input,
    .print-format input {
        display: none !important;
    }

    .print-format {
        font-family: Arial, Helvetica, sans-serif;
        font-size: 10pt;
        color: #000;
        line-height: 1.4;
        padding: 0;
        margin: 0;
    }

    .voucher-title {
        text-align: center;
        font-size: 16pt;
        font-weight: bold;
        border: 2px solid #000;
        padding: 12px;
        margin-bottom: 15px;
    }

    .company-row {
        width: 100%;
        border-collapse: collapse;
        margin-bottom: 10px;
    }

    .company-row td.label {
        background-color: #5b9bd5;
        color: white;
        font-weight: bold;
        padding: 8px 15px;
        width: 100px;
        border: 1px solid #000;
    }

    .company-row td.value {
        padding: 8px 15px;
        border: 1px solid #000;
        text-align: center;
        font-weight: bold;
    }

    .details-row {
        width: 100%;
        border-collapse: collapse;
        margin-bottom: 10px;
    }

    .details-row > tbody > tr > td {
        vertical-align: top;
        width: 50%;
        padding: 0;
    }

    .details-row > tbody > tr > td:first-child {
        padding-right: 5px;
    }

    .details-row > tbody > tr > td:last-child {
        padding-left: 5px;
    }

    .section-box {
        border: 1px solid #000;
        width: 100%;
    }

    .section-header {
        background-color: #5b9bd5;
        color: white;
        font-weight: bold;
        padding: 6px 10px;
        text-align: center;
        font-size: 10pt;
        border-bottom: 1px solid #000;
    }

    .section-content {
        padding: 0;
    }

    .info-row {
        display: table;
        width: 100%;
        border-bottom: 1px solid #000;
    }

    .info-row:last-child {
        border-bottom: none;
    }

    .info-label {
        display: table-cell;
        width: 130px;
        padding: 5px 8px;
        vertical-align: top;
        border-right: 1px solid #000;
    }

    .info-colon {
        display: table-cell;
        width: 15px;
        padding: 5px 5px;
        text-align: center;
        border-right: 1px solid #000;
    }

    .info-value {
        display: table-cell;
        padding: 5px 8px;
        vertical-align: top;
    }

    .section-title {
        font-size: 11pt;
        font-weight: bold;
        margin: 15px 0 8px 0;
        padding: 5px 0;
        border-bottom: 1px solid #000;
    }

    .invoice-table {
        width: 100%;
        border-collapse: collapse;
        margin-bottom: 15px;
        font-size: 10pt;
    }

    .invoice-table th {
        background-color: #5b9bd5;
        color: white;
        padding: 8px 5px;
        text-align: center;
        font-weight: bold;
        border: 1px solid #000;
    }

    .invoice-table td {
        padding: 6px 5px;
        border: 1px solid #000;
        vertical-align: middle;
    }

    .invoice-table .text-right {
        text-align: right;
    }

    .invoice-table .text-center {
        text-align: center;
    }

    .total-row {
        font-weight: bold;
    }

    .debit-note-row td {
        color: #000;
    }

    .payment-history-table {
        width: 100%;
        border-collapse: collapse;
        margin-bottom: 15px;
        font-size: 9pt;
    }

    .payment-history-table th {
        background-color: #5b9bd5;
        color: white;
        padding: 6px 4px;
        text-align: center;
        font-weight: bold;
        border: 1px solid #000;
    }

    .payment-history-table td {
        padding: 5px 4px;
        border: 1px solid #000;
        text-align: center;
    }

    .signature-section {
        margin-top: 30px;
    }

    .signature-table {
        width: 100%;
        border-collapse: collapse;
    }

    .signature-table td {
        width: 50%;
        padding: 30px 15px 10px 15px;
        text-align: center;
        border: 1px solid #000;
        vertical-align: bottom;
    }

    .signature-line {
        border-top: 1px solid #000;
        margin: 0 20px;
        padding-top: 5px;
        font-size: 10pt;
    }

    .amount-negative {
        color: #000;
    }

    .attachment-section {
        page-break-before: always;
    }

    .attachment-header {
        font-size: 11pt;
        font-weight: bold;
        margin: 10px 0;
        padding: 5px 0;
        border-bottom: 1px solid #000;
    }

    .pdf-page-image {
        max-width: 100%;
        height: auto;
        display: block;
        margin: 5px auto;
        border: 1px solid #ccc;
    }

    .po-section {
        page-break-before: always;
    }

    .po-header {
        font-size: 11pt;
        font-weight: bold;
        margin: 10px 0;
        padding: 5px 0;
        border-bottom: 1px solid #000;
    }

    .costing-section {
        page-break-before: always;
    }

    .costing-header {
        font-size: 11pt;
        font-weight: bold;
        margin: 10px 0;
        padding: 5px 0;
        border-bottom: 1px solid #000;
    }

    .prev-payment-section {
        page-break-before: always;
    }

    .prev-payment-header {
        font-size: 11pt;
        font-weight: bold;
        margin: 10px 0;
        padding: 5px 0;
        border-bottom: 1px solid #000;
    }
</style>

<div class="print-format">

    <!-- Payment Voucher Title -->
    <div class="voucher-title">
        {% if is_tr_payment %}
            APPLICATION FOR TRUST RECEIPT PAYMENT
        {% elif is_lc_payment %}
            APPLICATION FOR LETTER OF CREDIT PAYMENT
        {% else %}
            PAYMENT VOUCHER
        {% endif %}
    </div>

    <!-- Company Row -->
    <table class="company-row">
        <tr>
            <td class="label">Company</td>
            <td class="value">{{ doc.company }}</td>
        </tr>
    </table>

    <!-- Issued Bank Details & Voucher Details -->
    <table class="details-row">
        <tr>
            <td>
                <div class="section-box">
                    <div class="section-header">ISSUED BANK DETAILS</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">Issued Bank</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ issued_bank_details.bank or doc.issued_bank or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Account No.</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ issued_bank_details.bank_account_no or issued_bank_details.iban or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Currency</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ issued_bank_currency }}</span>
                        </div>
                    </div>
                </div>
            </td>
            <td>
                <div class="section-box">
                    <div class="section-header">VOUCHER DETAILS</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">Voucher No.</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.name }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Voucher Date</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ frappe.utils.formatdate(doc.posting_date, "d-M-yyyy") }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Payment Mode</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.payment_mode or "TR" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Cheque Date</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ frappe.utils.formatdate(doc.cheque_date, "d-M-yyyy") if doc.cheque_date else "N/A" }}</span>
                        </div>
                    </div>
                </div>
            </td>
        </tr>
    </table>

    <!-- Supplier Details & Bank Details -->
    <table class="details-row">
        <tr>
            <td>
                <div class="section-box">
                    <div class="section-header">{{ party_label|upper }} DETAILS</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">{{ party_label }} Name</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ party_name }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Address</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ party_address }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Telephone</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.telephone or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">E-Mail</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.email or "" }}</span>
                        </div>
                    </div>
                </div>
            </td>
            <td>
                <div class="section-box">
                    <div class="section-header">BANK DETAILS (for TT/ TR Payments)</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">Bank Account No.</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ supplier_bank.bank_account_no or supplier_bank.iban or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Bank Account Name</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ supplier_bank.name or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Bank Name</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ supplier_bank.bank or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">SWIFT Code</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ supplier_swift }}</span>
                        </div>
                    </div>
                </div>
            </td>
        </tr>
    </table>

    <!-- TR/LC Details Section (Only shown when is_tr_lc_payment is checked) -->
    {% if doc.is_tr_lc_payment %}
    <div class="section-title">TRUST RECEIPT DETAILS</div>

    <table class="details-row">
        <tr>
            <td>
                <div class="section-box">
                    <div class="section-header">TR/LC INFORMATION</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">TR Amount & Currency</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">
                                {% set total_amount = 0 %}
                                {% for row in doc.payment_references %}
                                    {% set total_amount = total_amount + (row.base_outstanding_amount or row.base_grand_total or 0) %}
                                {% endfor %}
                                {{ doc.currency or company_currency }} {{ frappe.utils.fmt_money(total_amount, currency=doc.currency or company_currency) }}
                            </span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Type of TR</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.tr_type or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Port of Loading</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.port_of_loading or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Port of Discharge</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.port_of_discharge or "" }}</span>
                        </div>
                    </div>
                </div>
            </td>
            <td>
                <div class="section-box">
                    <div class="section-header">SHIPMENT DETAILS</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">COO of Goods</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.coo_of_goods or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Mode of Shipment</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.mode_of_shipment or "" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Brief Description</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ doc.goods_description or "" }}</span>
                        </div>
                    </div>
                </div>
            </td>
        </tr>
    </table>

    <!-- Documents Section -->
    <table class="details-row">
        <tr>
            <td>
                <div class="section-box">
                    <div class="section-header" style="background-color: #92d050;">YES</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">Proforma Invoice</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ "Y" if doc.has_proforma_invoice else "N" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Purchase Order</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ "Y" if doc.has_purchase_order else "N" }}</span>
                        </div>
                    </div>
                </div>
            </td>
            <td>
                <div class="section-box">
                    <div class="section-header" style="background-color: #f4b084;">DOCUMENTS REQUIRED (FOR OPEN TR)</div>
                    <div class="section-content">
                        <div class="info-row">
                            <span class="info-label">Commercial Invoice</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ "Y" if doc.has_commercial_invoice else "N" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">BL / AWB</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ "Y" if doc.has_bl_awb else "N" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Delivery Note</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ "Y" if doc.has_delivery_note else "N" }}</span>
                        </div>
                        <div class="info-row">
                            <span class="info-label">Bill of Entry</span>
                            <span class="info-colon">:</span>
                            <span class="info-value">{{ "Y" if doc.has_bill_of_entry else "N" }}</span>
                        </div>
                    </div>
                </div>
            </td>
        </tr>
    </table>

    <!-- Reference -->
    <div style="margin: 10px 0; padding: 5px; border: 1px solid #000;">
        <strong>Ref:</strong> {{ doc.name }}
    </div>
    {% endif %}

    <!-- Invoice Summary Section -->
    <div class="section-title">Invoice Details</div>

    <table class="invoice-table">
        <thead>
            <tr>
                <th style="width: 35px;">SINo</th>
                <th style="width: 120px;">Inv. No.</th>
                <th style="width: 75px;">Inv. Date</th>
                <th style="width: 75px;">Due Date</th>
                <th style="width: 45px;">Curr.</th>
                <th style="width: 90px;">Amount (FC)</th>
                <th style="width: 90px;">Amount ({{ company_currency }})</th>
                <th>Remarks</th>
            </tr>
        </thead>
        <tbody>
            {% set total_base = {'value': 0} %}
            {% set currency_totals = {} %}

            {% for row in doc.payment_references %}
            {% set is_debit = row.is_return or row.reference_doctype == "Debit Note" %}
            {% set amount_fc = row.outstanding_amount or row.grand_total or 0 %}
            {% set amount_base = row.base_outstanding_amount or row.base_grand_total or 0 %}

            {% set curr = row.currency or company_currency %}
            {% if curr not in currency_totals %}
                {% set _ = currency_totals.update({curr: {'fc': 0, 'base': 0}}) %}
            {% endif %}
            {% set _ = currency_totals[curr].update({'fc': currency_totals[curr]['fc'] + amount_fc}) %}
            {% set _ = total_base.update({'value': total_base['value'] + amount_base}) %}

            <tr class="{{ 'debit-note-row' if is_debit else '' }}">
                <td class="text-center">{{ loop.index }}</td>
                <td>{{ row.reference_name }}</td>
                <td class="text-center">{{ frappe.utils.formatdate(row.invoice_date, "dd-MM-yyyy") if row.invoice_date else "" }}</td>
                <td class="text-center">{{ frappe.utils.formatdate(row.due_date, "dd-MM-yyyy") if row.due_date else "" }}</td>
                <td class="text-center">{{ row.currency or company_currency }}</td>
                <td class="text-right {{ 'amount-negative' if is_debit else '' }}">
                    {{ frappe.utils.fmt_money(amount_fc, currency=row.currency) }}
                </td>
                <td class="text-right {{ 'amount-negative' if is_debit else '' }}">
                    {{ frappe.utils.fmt_money(amount_base, currency=company_currency) }}
                </td>
                <td>{{ row.remarks or row.document_reference or "" }}</td>
            </tr>
            {% endfor %}

            <tr class="total-row">
                <td colspan="5" class="text-center"><strong>TOTAL</strong></td>
                <td class="text-right">
                    {% for curr, amounts in currency_totals.items() %}
                    {{ frappe.utils.fmt_money(amounts['fc'], currency=curr) }}{% if not loop.last %}<br>{% endif %}
                    {% endfor %}
                </td>
                <td class="text-right">{{ frappe.utils.fmt_money(total_base['value'], currency=company_currency) }}</td>
                <td></td>
            </tr>
        </tbody>
    </table>

    <!-- Previous Payment Details Section (Table) -->
    {% if payment_history and payment_history|length > 0 %}
    <div class="section-title">Previous Payment Details</div>

    <table class="payment-history-table">
        <thead>
            <tr>
                <th style="width: 30px;">Sl.</th>
                <th style="width: 75px;">Bank</th>
                <th style="width: 35px;">Type</th>
                <th style="width: 110px;">Voucher No.</th>
                <th style="width: 75px;">Date</th>
                <th style="width: 100px;">Beneficiary</th>
                <th style="width: 105px;">IBAN/Account</th>
                <th style="width: 85px;">Debit Account</th>
                <th style="width: 40px;">Curr.</th>
                <th style="width: 85px;">Amount</th>
            </tr>
        </thead>
        <tbody>
            {% for payment in payment_history[:10] %}
            <tr>
                <td>{{ loop.index }}</td>
                <td style="text-align: left; padding-left: 5px;">{{ payment.bank or "" }}</td>
                <td>{{ payment.type or "TR" }}</td>
                <td style="text-align: left; padding-left: 5px;">{{ payment.voucher_no or "" }}</td>
                <td>{{ frappe.utils.formatdate(payment.date, "dd-MM-yyyy") if payment.date else "" }}</td>
                <td style="text-align: left; padding-left: 5px;">{{ payment.beneficiary or "" }}</td>
                <td style="text-align: left; padding-left: 5px; font-size: 8pt;">{{ payment.beneficiary_account or "" }}</td>
                <td style="text-align: left; padding-left: 5px; font-size: 8pt;">{{ payment.debit_account or "" }}</td>
                <td>{{ payment.currency or company_currency }}</td>
                <td style="text-align: right;">{{ frappe.utils.fmt_money(payment.amount, currency=payment.currency) }}</td>
            </tr>
            {% endfor %}
        </tbody>
    </table>
    {% endif %}

    <!-- Previous Payment Details Attachment (from first row) - shown after table or in place of it -->
    {% if prev_payment_images|length > 0 %}
    <div class="prev-payment-section">
        <div class="prev-payment-header">Previous Payment Details (Attachment)</div>
        {% for img_data in prev_payment_images %}
            <img src="{{ img_data }}" class="pdf-page-image" />
        {% endfor %}
    </div>
    {% endif %}

    <!-- Remarks Section -->
    {% if doc.remarks %}
    <div class="section-title">Remarks</div>
    <div style="padding: 10px; border: 1px solid #000; font-size: 10pt;">
        {{ doc.remarks }}
    </div>
    {% endif %}

    <!-- Signature Section -->
    <div class="signature-section">
        <table class="signature-table">
            <tr>
                <td>
                    <div class="signature-line">Prepared by / Authorized by: ACCOUNTS MANAGER</div>
                </td>
                <td>
                    <div class="signature-line">Approved by: FINANCE MANAGER</div>
                </td>
            </tr>
            <tr>
                <td>
                    <div class="signature-line">Approved by: GENERAL MANAGER</div>
                </td>
                <td>
                    <div class="signature-line">Approved by: MANAGING DIRECTOR</div>
                </td>
            </tr>
        </table>
    </div>

    {# ═══════════ REFERENCE DOCUMENT ATTACHMENTS (all party types) - using batch pre-fetch ═══════════ #}
    {% set ref_label_map = {"Purchase Invoice": "Supplier Invoice", "Debit Note": "Debit Note", "Credit Note": "Credit Note", "Sales Invoice": "Sales Invoice", "Expense Claim": "Expense Claim", "Payment Entry": "Payment Entry", "Journal Entry": "Journal Entry", "Purchase Order": "Purchase Order"} %}

    {% for row in doc.payment_references %}
        {% if row.reference_doctype and row.reference_doctype != "Manual" and row.reference_name %}
            {% set ref_images = all_attachments.get("ref_images", {}).get(loop.index0|string, []) %}
            {% if ref_images|length > 0 %}
            <div class="attachment-section">
                <div class="attachment-header">{{ ref_label_map.get(row.reference_doctype, row.reference_doctype) }}: {{ row.reference_name }}</div>
                {% for img_data in ref_images %}
                    <img src="{{ img_data }}" class="pdf-page-image" />
                {% endfor %}
            </div>
            {% endif %}
        {% endif %}
    {% endfor %}

    {# ═══════════ SUPPLIER-SPECIFIC: Linked Purchase Orders ═══════════ #}
    {% if doc.party_type == "Supplier" %}
    {# Linked Purchase Orders - using batch pre-fetch #}
    {% for row in doc.payment_references %}
        {% set po_data = all_attachments.get("po_images", {}).get(loop.index0|string, {}) %}
        {% if po_data and po_data.get("images") %}
        <div class="po-section">
            <div class="po-header">Purchase Order: {{ po_data.get("po_name", "") }}</div>
            {% for img_data in po_data.get("images", []) %}
                <img src="{{ img_data }}" class="pdf-page-image" />
            {% endfor %}
        </div>
        {% endif %}
    {% endfor %}

    {# Costing Sheets - using batch pre-fetch #}
    {% for row in doc.payment_references %}
        {% set costing_images = all_attachments.get("costing_images", {}).get(loop.index0|string, []) %}
        {% if costing_images|length > 0 %}
        <div class="costing-section">
            <div class="costing-header">Costing Sheet: {{ row.reference_name }}</div>
            {% for img_data in costing_images %}
                <img src="{{ img_data }}" class="pdf-page-image" />
            {% endfor %}
        </div>
        {% endif %}
    {% endfor %}

    {# ═══════════ SUPPLIER BANK LETTER - using batch pre-fetch ═══════════ #}
    {% set bank_letter_images = all_attachments.get("bank_letter_images", []) %}
    {% if bank_letter_images|length > 0 %}
    <div class="attachment-section">
        <div class="attachment-header">Bank Letter: {{ party_name }}</div>
        {% for img_data in bank_letter_images %}
            <img src="{{ img_data }}" class="pdf-page-image" />
        {% endfor %}
    </div>
    {% endif %}
    {% endif %}

    {# ═══════════ ADDITIONAL DOCUMENTS (always last) - using batch pre-fetch ═══════════ #}
    {% set addl_doc_data = all_attachments.get("additional_doc_images", {}) %}
    {% for addl_doc in (doc.additional_documents or []) %}
        {% set addl_entry = addl_doc_data.get(loop.index0|string, {}) %}
        {% if addl_entry and addl_entry.get("images") %}
        <div class="attachment-section">
            <div class="attachment-header">{{ addl_entry.get("label", "Additional Document") }}</div>
            {% for img_data in addl_entry.get("images", []) %}
                <img src="{{ img_data }}" class="pdf-page-image" />
            {% endfor %}
        </div>
        {% endif %}
    {% endfor %}
</div>
